def connected_components_dfs(graph: dict) -> list:
    visited = set()
    components = []

    for start in graph:
        if start in visited:
            continue
        # Iterative DFS
        component = set()
        stack = [start]
        while stack:
            node = stack.pop()
            if node in visited:
                continue
            visited.add(node)
            component.add(node)
            for neighbor in graph[node]:
                if neighbor not in visited:
                    stack.append(neighbor)
        components.append(component)

    return components


class UnionFind:
    def __init__(self, nodes):
        self.parent = {node: node for node in nodes}
        self.rank = {node: 0 for node in nodes}

    def find(self, x):
        # Path compression: make every node point directly to the root
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y) -> None:
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return  # Already in the same component
        # Union by rank: attach smaller tree under larger tree
        if self.rank[rx] < self.rank[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]:
            self.rank[rx] += 1

    def get_components(self) -> list:
        from collections import defaultdict
        root_to_members = defaultdict(set)
        for node in self.parent:
            root = self.find(node)
            root_to_members[root].add(node)
        return list(root_to_members.values())


def connected_components_union_find(graph: dict) -> list:
    uf = UnionFind(graph.keys())
    for node in graph:
        for neighbor in graph[node]:
            uf.union(node, neighbor)
    return uf.get_components()

